solution:
function myIndexOf(s, p) {
  for (let i = 0; i + p.length <= s.length; i++) {
    let k = 0;
    while (k < p.length && s[i + k] === p[k]) k++;
    if (k === p.length) return i;
  }
  return -1;
}

